    52→/* ------------------------------------------------------------------ */
    53→/* Representative 100-point test suite                                */
    54→/* ------------------------------------------------------------------ */
    55→
    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (7) --- */
    59→    emit(0.0);                               /* acos(0) = pi/2 */
    60→    emit(-0.0);                              /* acos(-0) = pi/2 */
    61→    emit_u(0x7ff8000000000000ULL);           /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);           /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);           /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);           /* +Inf (domain error -> NaN) */
    65→    emit_u(0xfff0000000000000ULL);           /* -Inf (domain error -> NaN) */
    66→
    67→    /* --- Section 2: Subnormal inputs (6) --- */
    68→    /* Subnormals are in (-1,1), so acos is defined; result is very near pi/2 */
    69→    emit_u(0x0000000000000001ULL);           /* min positive subnormal: 2^-1074 */
    70→    emit_u(0x8000000000000001ULL);           /* min negative subnormal */
    71→    emit_u(0x0008000000000000ULL);           /* mid positive subnormal */
    72→    emit_u(0x8008000000000000ULL);           /* mid negative subnormal */
    73→    emit_u(0x000fffffffffffffULL);           /* max positive subnormal: just below DBL_MIN */
    74→    emit_u(0x800fffffffffffffULL);           /* max negative subnormal */
    75→
    76→    /* --- Section 3: Domain boundary: exact +/-1 and out-of-domain inputs (8) --- */
    77→    emit(1.0);                               /* acos(1) = 0 (exact boundary) */
    78→    emit(-1.0);                              /* acos(-1) = pi (exact boundary) */
    79→    emit_u(0x3fefffffffffffffULL);           /* one ULP below 1.0 (inside domain) */
    80→    emit_u(0x3ff0000000000001ULL);           /* one ULP above 1.0 (outside domain -> NaN) */
    81→    emit_u(0xbfefffffffffffffULL);           /* one ULP above -1.0 (inside domain) */
    82→    emit_u(0xbff0000000000001ULL);           /* one ULP below -1.0 (outside domain -> NaN) */
    83→    emit(2.0);                               /* outside domain -> NaN */
    84→    emit(-2.0);                              /* outside domain -> NaN */
    85→
    86→    /* --- Section 4: Near 1.0 ULP density (8) --- */
    87→    emit_u(0x3ff0000000000000ULL);           /* 1.0 exactly */
    88→    emit_u(0x3fefffffffffffffULL);           /* 1 ULP below 1.0 */
    89→    emit_u(0x3feffffffffffffeULL);           /* 2 ULPs below 1.0 */
    90→    emit_u(0x3feffffffffffff0ULL);           /* a few ULPs below 1.0 */
