    96→    /* --- Section 5: Near -1.0 ULP density (6) --- */
    97→    emit_u(0xbff0000000000000ULL);           /* -1.0 exactly */
    98→    emit_u(0xbfefffffffffffffULL);           /* 1 ULP toward zero from -1.0 */
    99→    emit_u(0xbfeffffffffffffeULL);           /* 2 ULPs toward zero from -1.0 */
   100→    emit_u(0xbfeffffffffffff0ULL);           /* a few ULPs toward zero from -1.0 */
   101→    emit_u(0xbfefffffff000000ULL);           /* moderately above -1.0 */
   102→    emit_u(0xbfeff80000000000ULL);           /* -1.0 + ~2^-9 */
