   104→    /* --- Section 6: Known mathematical key values (14) --- */
   105→    /* acos(sqrt(3)/2) = pi/6; acos(sqrt(2)/2) = pi/4; acos(0.5) = pi/3; acos(0) = pi/2 */
   106→    emit(0.5);                               /* acos(0.5) = pi/3 = 60 deg */
