   114→    emit_u(0xbfd0000000000000ULL);           /* -0.25 */
   115→    emit_u(0x3fc0000000000000ULL);           /* 0.125 */
   116→    emit_u(0xbfc0000000000000ULL);           /* -0.125 */
   117→    emit_u(0x3fe921fb54442d18ULL);           /* pi/4 ~ 0.7854 (as input) */
   118→    emit_u(0x3fde147ae147ae14ULL);           /* 0.47: near midpoint of [0,0.5] */
