   122→    /* Many acos implementations switch algorithms at |x| = 0.5 */
   123→    emit_u(0x3fe0000000000000ULL);           /* 0.5 exactly */
   124→    emit_u(0xbfe0000000000000ULL);           /* -0.5 exactly */
   125→    emit_u(0x3fdffffffffffffeULL);           /* 1 ULP below 0.5 (just inside lower interval) */
